class LCA
{
public:
	LCA(int n, const vector<vector<int>>& e, const vector<int>& dis)
	{
		f.assign(n + 10, vector<int>(31));
		depth.assign(n + 10, 0);
		dp1.assign(n + 10, vector<ll>(31));
		dp2.assign(n + 10, vector<ll>(31));
		init(1, 0, e, dis);
	}

	int lca(int x, int y)
	{
		if (depth[x] < depth[y])swap(x, y);
		for (int i = 29; i >= 0; i--)
			if (depth[x] - (1 << i) >= depth[y])
				x = f[x][i];
		if (x == y) return x;
		for (int i = 29; i >= 0; i--)
			if (f[x][i] != f[y][i])
				x = f[x][i], y = f[y][i];
		return f[x][0];
	}

	int get_dis(int x, int y) {
		int f = lca(x, y);
		return depth[x] - depth[f] + depth[y] - depth[f];
	}

	ll query(int x, int y) {
		const ll DISXY = get_dis(x, y);
		ll addx = DISXY + depth[x];
		ll addy = 2 * DISXY - depth[y];

		bool change = 0;
		if (depth[x] < depth[y])swap(x, y), change = 1;

		ll res = 2 * DISXY;
		fb(i, 29, 0)
			if (depth[f[x][i]] >= depth[y]) {
				// 注意这里需接着对 x,y 进行处理
				if (!change)res = min(res, dp1[x][i] + addx);
				else res = min(res, dp2[x][i] + addy);
				x = f[x][i];
			}

		if (x == y) {
			if (!change)res = min({ res, dp1[x][0] + addx, dp2[y][0] + addy });
			else res = min({ res, dp2[x][0] + addy, dp1[y][0] + addx });
			return res;
		}

		fb(i, 29, 0)
			if (f[x][i] != f[y][i]) {
				if (!change)res = min({ res, dp1[x][i] + addx, dp2[y][i] + addy });
				else res = min({ res, dp2[x][i] + addy, dp1[y][i] + addx });
				x = f[x][i], y = f[y][i];
			}

		// 注意这里需接着对 x,y,lca(x,y) 进行处理
		if (!change)res = min({ res, dp1[x][0] + addx, dp2[y][0] + addy });
		else res = min({ res, dp2[x][0] + addy, dp1[y][0] + addx });

		int lca = f[x][0];
		if (!change)res = min({ res, dp1[lca][0] + addx, dp2[lca][0] + addy });
		else res = min({ res, dp2[lca][0] + addy, dp1[lca][0] + addx });

		return res;
	}
private:
	vector<int> depth;
	vector<vector<int>> f;
	vector<vector<ll>> dp1, dp2;

	void init(int now, int fa, const vector<vector<int>>& e, const vector<int>& dis)
	{
		f[now][0] = fa;
		depth[now] = depth[fa] + 1;
		dp1[now][0] = 3ll * dis[now] - depth[now];
		dp2[now][0] = 3ll * dis[now] + depth[now];

		for (int i = 1; (1 << i) <= depth[now]; i++) {
			f[now][i] = f[f[now][i - 1]][i - 1];

			dp1[now][i] = min(dp1[now][i - 1], dp1[f[now][i - 1]][i - 1]);
			dp2[now][i] = min(dp2[now][i - 1], dp2[f[now][i - 1]][i - 1]);
		}

		for (int to : e[now]) {
			if (to == fa)continue;
			init(to, now, e, dis);
		}
	}
};
