	fa(i, 1, n - 1) {
		int x, y; cin >> x >> y;
		g[x].pb(y), g[y].pb(x);
	}
	var dis = vector<int>(n + 1, INF);
	var Q = queue<pii>();
	fa(i, 1, k) {
		int x; cin >> x;
		Q.push({ x, dis[x] = 0 });
	}
	while (Q.size()) {
		var[now, d] = Q.front();
		Q.pop();
		if (d > dis[now])continue;
		for (int to : g[now]) {
			if (dis[to] > dis[now] + 1) {
				dis[to] = dis[now] + 1;
				Q.push({ to, dis[to] });
			}
		}
	}
	var lca = LCA(n, g, dis);
	int q; cin >> q;
	while (q--) {
		int x, y; cin >> x >> y;
		cout << lca.query(x, y) << endl;
	}
	return;
